B.Q1=new A.U(B.ac,"Tense signals when an action happens","In aviation English, choosing the right tense is critical. ATC uses **present simple** for permanent facts, **present continuous** for current actions, and **past simple** for completed events in reports.\n\nMixing tenses in checklists or reports is a common exam error.",null,null,null)
B.LD=new A.os(4,"tensesTimeline")
B.Q2=new A.U(B.eW,"Tenses on a timeline",null,null,B.LD,null)
B.P5=new A.U(B.B,"Simple vs. Continuous",'**Present Simple** \u2014 facts, routines, permanent states\n\u2192 "The ILS localizer **operates** on frequencies 108\u2013111.95 MHz."\n\n**Present Continuous** \u2014 actions happening now, temporary\n\u2192 "The aircraft **is climbing** through flight level 180."\n\n**Past Simple** \u2014 completed events (reports, logs)\n\u2192 "The crew **performed** the before-start checklist at 0612Z."\n\n**Past Continuous** \u2014 ongoing past action interrupted\n\u2192 "The aircraft **was taxiing** when the bird strike **occurred**."',null,null,null)
B.Kq=new A.aE("The aircraft is currently holding at ELVIN fix due to traffic congestion.","U\xe7ak, trafik yo\u011funlu\u011fu nedeniyle \u015fu anda ELVIN noktas\u0131nda bekleme yap\u0131yor.","is currently holding")
B.KS=new A.aE("The crew completed the after-landing checklist at 14:32 UTC.","Ekip ini\u015f sonras\u0131 kontrol listesini 14:32 UTC'de tamamlad\u0131.","completed")
B.Kw=new A.aE("ATIS information Bravo states that the active runway is 36L.","ATIS bilgisi Bravo, aktif pistin 36L oldu\u011funu belirtiyor.","states")
B.TE=s([B.Kq,B.KS,B.Kw],t.l)
B.Qm=new A.U(B.ad,"Tense in Context",null,B.TE,null,null)
B.PQ=new A.U(B.ae,"\u2708\ufe0f Exam Tip","Time signal words give away the tense:\n\u2022 **now / currently / at the moment** \u2192 present continuous\n\u2022 **always / usually / every flight** \u2192 present simple\n\u2022 **at 14:32 / yesterday / last night** \u2192 past simple\n\u2022 **while / when / as** \u2192 look for two simultaneous past actions\n\nAviation logs and reports always use **past simple** \u2014 they record completed events.",null,null,null)
