B.a2p=new A.aa(-151,B.aF,761,"Doors and slides \u2014 \u2026\u2026\u2026\u2026 and cross-checked.",B.Vq,0,B.L,null,null,null)
B.V0=s(["Verify","Check","Set","Calibrate"],t.s)
B.a39=new A.aa(-152,B.aF,762,"\u2026\u2026\u2026\u2026 the standby altimeter to the current field elevation.",B.V0,2,B.A,null,null,null)
B.Xl=s(["set","verify","arm","select"],t.s)
B.a1H=new A.aa(-153,B.aF,763,"After engine start, \u2026\u2026\u2026\u2026 the engine oil pressure is within normal limits.",B.Xl,1,B.A,null,null,null)
