B.Qa=new A.U(B.ad,"Translation Examples",null,B.Vk,null,null)
B.Qw=new A.U(B.ae,"\u2708\ufe0f Translation Tips",'Common translation mistakes to avoid:\n\u2022 "Hold position" \u2260 "pisti tutun" \u2192 Correct: "bulundu\u011funuz yerde bekleyin"\n\u2022 "Expedite" \u2260 "acele edin" \u2192 Correct: "m\xfcmk\xfcn olan en k\u0131sa s\xfcrede (yap\u0131n)"\n\u2022 "Wilco" \u2260 "tamam" \u2192 Correct: "anl\u0131yorum ve gere\u011fini yapaca\u011f\u0131m"\n\u2022 "Roger" = "mesaj\u0131n\u0131z al\u0131nd\u0131" (not agreement, just acknowledgement)',null,null,null)
B.Sf=s(["Etrafta d\xf6n","Al\xe7al\u0131\u015f prosed\xfcr\xfcn\xfc iptal et ve t\u0131rman\u0131\u015f yap","Pist\u0131n \xe7evresinde u\xe7","Sola d\xf6n"],t.s)
