B.Qy=new A.U(B.ac,"ATIS delivers critical pre-flight information","ATIS (Automatic Terminal Information Service) broadcasts updated airport information continuously. Pilots must obtain the current ATIS information before contacting ATC and must confirm they have received it with the ATIS letter (Alpha, Bravo, Charlie\u2026).\n\nReading comprehension questions often use ATIS-style texts and ask you to extract specific information.",null,null,null)
B.OC=new A.U(B.B,"\ud83d\udcfb Standard ATIS Content",'An ATIS broadcast includes (in order):\n1. Airport name and ATIS information letter\n2. Observation time\n3. Active runway(s) in use\n4. Approach type in use (ILS/VOR/Visual)\n5. Wind direction and speed\n6. Visibility\n7. Weather phenomena\n8. Cloud layers\n9. Temperature and dewpoint\n10. QNH\n11. NOTAMs/special notices\n12. "Advise on initial contact you have information [letter]"',null,null,null)
B.KJ=new A.aE("Istanbul Atat\xfcrk information Alpha. Time 0650 UTC. Runway in use: 36L for landing, 36R for takeoff.","\u0130stanbul Atat\xfcrk, bilgi Alfa. Saat 0650 UTC. Kullan\u0131lan pist: ini\u015f i\xe7in 36L, kalk\u0131\u015f i\xe7in 36R.","information Alpha")
B.Ka=new A.aE("ILS approach in use for runway 36L. Transition level: FL60.","Pist 36L i\xe7in ILS yakla\u015fmas\u0131 kullan\u0131lmaktad\u0131r. Ge\xe7i\u015f seviyesi: FL60.","Transition level")
