B.Pd=new A.U(B.ac,"Reported speech in aviation reports","Aviation incident and accident reports frequently quote what crew members or controllers **said** or **thought**. The grammar used to report these statements is called **indirect/reported speech**.\n\nExam questions often ask you to convert between direct and reported speech, or complete a reported speech sentence correctly.",null,null,null)
B.Q6=new A.U(B.eW,"Watch the tense shift",null,null,B.qQ,null)
B.PO=new A.U(B.B,"Tense Backshift Rule",'When the reporting verb is **past** (said, told, reported), tenses shift back:\n\n| Direct | Reported |\n|---|---|\n| is/am/are | **was/were** |\n| was/were | **had been** |\n| will | **would** |\n| can | **could** |\n| must | **had to** |\n| has/have + V3 | **had** + V3 |\n\n"The system **is** malfunctioning." \u2192\nThe pilot said the system **was** malfunctioning.',null,null,null)
B.K6=new A.aE("The captain reported that the hydraulic pressure had dropped below limits.","Kaptan, hidrolik bas\u0131nc\u0131n limitin alt\u0131na d\xfc\u015ft\xfc\u011f\xfcn\xfc bildirdi.","had dropped")
B.L6=new A.aE("ATC informed the crew that the runway was temporarily closed.","ATC ekibe pistin ge\xe7ici olarak kapat\u0131ld\u0131\u011f\u0131n\u0131 bildirdi.","was temporarily closed")
B.KO=new A.aE("The maintenance engineer said he would complete the inspection by 0600.","Bak\u0131m m\xfchendisi incelemeyi 06:00'ya kadar tamamlayaca\u011f\u0131n\u0131 s\xf6yledi.","would complete")
B.RP=s([B.K6,B.L6,B.KO],t.l)
B.Qz=new A.U(B.ad,"Aviation Reported Speech",null,B.RP,null,null)
B.Qs=new A.U(B.ae,"\u2708\ufe0f Exam Tip",'Key reporting verbs and their prepositions:\n\u2022 said (that) \u2014 general statement\n\u2022 told + person + (that) \u2014 "told him/her"\n\u2022 reported (that) \u2014 formal/written report\n\u2022 informed + person + (that) \u2014 official notification\n\u2022 warned + person + (that/about) \u2014 hazard warning\n\nNo preposition after "said": \u2713 "said **that**" / \u2717 "said **to** him that"',null,null,null)
B.W5=s(["is","was","will be","has been"],t.s)
