B.QO=new A.U(B.ac,"Advanced vocabulary separates good from excellent","ICAO Level 5 and 6 proficiency requires mastery of low-frequency but high-stakes technical vocabulary. This lesson covers the terms that distinguish advanced candidates and that frequently appear in the hardest exam questions.",null,null,null)
B.Q9=new A.U(B.B,"\ud83c\udfc6 Advanced Operational Terms","**EDTO/ETOPS** \u2014 Extended Diversion Time Operations (flying far from alternate airports)\n**RVSM** \u2014 Reduced Vertical Separation Minima (300m / 1,000ft between FL290\u2013FL410)\n**PBN** \u2014 Performance-Based Navigation (RNP, RNAV specs)\n**MNPS** \u2014 Minimum Navigation Performance Specification (oceanic)\n**MEL** \u2014 Minimum Equipment List (approved deferred defects)\n**CDL** \u2014 Configuration Deviation List (approved structural deviations)\n**AOG** \u2014 Aircraft on Ground (urgent unserviceable aircraft)",null,null,null)
B.OB=new A.U(B.B,"\u26a0\ufe0f Safety-Critical Vocabulary","**Controlled flight into terrain (CFIT)** \u2014 aircraft in controlled flight strikes terrain\n**Loss of control in-flight (LOC-I)** \u2014 most fatal accident category\n**Runway incursion** \u2014 unauthorized presence on runway\n**Airspace infringement** \u2014 entering controlled airspace without clearance\n**Human factors** \u2014 study of human performance in aviation systems\n**Crew Resource Management (CRM)** \u2014 effective use of all resources\n**Threat and Error Management (TEM)** \u2014 proactive safety model",null,null,null)
B.KL=new A.aE("The accident was classified as CFIT \u2014 the crew was unaware of the proximity to terrain.","Kaza, CFIT olarak s\u0131n\u0131fland\u0131r\u0131ld\u0131 \u2014 ekip, araziye olan yak\u0131nl\u0131\u011f\u0131ndan habersizdi.","CFIT")
B.KG=new A.aE("Under RVSM, vertical separation between FL290 and FL410 is reduced to 1,000 feet.","RVSM kapsam\u0131nda, FL290 ile FL410 aras\u0131ndaki dikey ay\u0131rma 1.000 fite indirilmi\u015ftir.","RVSM")
B.Kj=new A.aE("The aircraft was dispatched on the MEL, with one hydraulic pump deferred.","U\xe7ak, bir hidrolik pompa ertelenmi\u015f olarak MEL'e g\xf6re hava arac\u0131 olarak g\xf6nderildi.","MEL")
B.V7=s([B.KL,B.KG,B.Kj],t.l)
B.Ow=new A.U(B.ad,"Expert Vocabulary in Context",null,B.V7,null,null)
B.R6=new A.U(B.ae,"\u2708\ufe0f Exam Strategy","For advanced vocabulary questions:\n\u2022 **EDTO/ETOPS** = about how far from alternates you can fly (oceanic/remote operations)\n\u2022 **MEL** = what you CAN fly with broken; **CDL** = approved structural missing parts\n\u2022 **PBN** includes both **RNAV** and **RNP** (RNP has on-board monitoring + alerting)\n\u2022 **Runway incursion** vs. **airspace infringement** \u2014 both are serious safety events but involve different areas\n\u2022 **CRM** is about **using available resources** \u2014 not just communication",null,null,null)
B.Th=s(["Crew Fatigue Incident Tracking","Controlled Flight Into Terrain","Cockpit Flight Information Terminal","Critical Flight Instrument Test"],t.s)
B.a1U=new A.aa(-260,B.ai,330,"CFIT stands for:",B.Th,1,B.A,null,null,null)
B.V2=s(["2,000 feet","500 meters","1,000 feet","600 meters"],t.s)
B.a3a=new A.aa(-261,B.ai,331,"Under RVSM, what is the minimum vertical separation between FL290 and FL410?",B.V2,2,B.A,null,null,null)
B.Wt=s(["Aircraft is on its way to the gate","Aircraft is grounded due to an unserviceable condition","Aircraft is authorized to operate with deferred defects","Aircraft has been overhauled"],t.s)
B.a1z=new A.aa(-262,B.ai,332,'An "AOG" status means:',B.Wt,1,B.A,null,null,null)
B.X1=s(["Aircraft landing on wrong runway","Any unauthorized presence on the runway","Runway excursion due to brake failure","ATC error causing runway conflict"],t.s)
