B.QE=new A.U(B.ac,"Procedure documents are dense with technical information","Standard Instrument Departures (SIDs) and Standard Terminal Arrival Routes (STARs) are documented procedures that contain altitudes, speeds, waypoints, and restrictions. Advanced reading questions use extracts from these documents and require precise interpretation.",null,null,null)
B.Pg=new A.U(B.B,"\ud83d\udeeb SID \u2014 Departure Procedure",'A SID (Standard Instrument Departure) provides:\n\u2022 Routing from runway to en-route structure\n\u2022 Altitude restrictions ("at or above 3,000 ft at waypoint TURPO")\n\u2022 Speed restrictions ("250 KIAS below 10,000 ft")\n\u2022 Transition codes (RNAV, conventional)\n\n**Altitude coding:**\n\u2022 **"A030+"** = at or above 3,000 ft\n\u2022 **"A050-"** = at or below 5,000 ft\n\u2022 **"A060B080"** = between 6,000 and 8,000 ft\n\u2022 **"S220"** = maintain speed 220 KIAS or below',null,null,null)
B.P4=new A.U(B.B,"\ud83d\udeec STAR \u2014 Arrival Procedure",'A STAR (Standard Terminal Arrival Route) provides:\n\u2022 Routing from en-route to terminal area / approach\n\u2022 Speed reduction profile\n\u2022 Transition to IAF (Initial Approach Fix)\n\n**Common STAR terminology:**\n\u2022 **IAF** \u2014 Initial Approach Fix (start of approach)\n\u2022 **IF** \u2014 Intermediate Fix\n\u2022 **FAF** \u2014 Final Approach Fix\n\u2022 **MAP** \u2014 Missed Approach Point\n\u2022 **Published hold** \u2014 holding pattern on procedure\n\u2022 **"Expect vectors"** \u2014 ATC will give radar headings instead',null,null,null)
B.KY=new A.aE("At or above 6,000 feet at TURPO waypoint before turning left to intercept the final approach course.","Final yakla\u015fma pistine girilmeden \xf6nce TURPO noktas\u0131nda 6.000 ft veya \xfczerinde olmak zorunludur.","At or above")
B.KK=new A.aE("Maintain 250 knots or less until 10 DME from the airport.","Havaliman\u0131ndan 10 DME mesafeye kadar 250 knot veya daha d\xfc\u015f\xfck h\u0131z koruyun.","Maintain 250 knots or less")
B.Ua=s([B.KY,B.KK],t.l)
B.Pp=new A.U(B.ad,"Procedure Language",null,B.Ua,null,null)
B.P6=new A.U(B.ae,"\u2708\ufe0f Exam Tip",'"At or above" / "at or below" in procedure documents:\n\u2022 "A030+" = at or **above** 3,000 ft (plus sign = higher)\n\u2022 "A050-" = at or **below** 5,000 ft (minus sign = lower)\n\nIf you see both a speed and altitude restriction at a waypoint, **both** must be complied with simultaneously.\n\n"Expect vectors" on a STAR does not mean ATC will always give vectors \u2014 it means the pilot should expect them (but must fly the published procedure if not given vectors).',null,null,null)
B.Us=s(["At 4,000 ft exactly","At or above 4,000 ft","At or below 4,000 ft","Between 4,000 and 4,500 ft"],t.s)
B.a2U=new A.aa(-270,B.aw,640,'In a SID procedure document, "A040+" means the aircraft must be:',B.Us,1,B.A,null,null,null)
B.T8=s(["The beginning of the missed approach","The start of the final approach segment","The runway threshold","The IAF position"],t.s)
B.a37=new A.aa(-271,B.aw,641,"The FAF (Final Approach Fix) marks:",B.T8,1,B.A,null,null,null)
B.Xf=s(["Vectors will definitely be given by ATC","The pilot should anticipate radar vectors but fly published procedure if not given","Vectors are not available on this route","The pilot may request vectors"],t.s)
B.a2i=new A.aa(-272,B.aw,642,'"Expect vectors" on a STAR means:',B.Xf,1,B.b_,null,null,null)
B.Ts=s(["Climb to speed 220 knots","Maintain 220 KIAS or less","Set Mach 0.220","Not exceed 220 feet per minute climb"],t.s)
B.a1P=new A.aa(-273,B.aw,643,'If a SID shows "S220" at a waypoint, the crew must:',B.Ts,1,B.b_,null,null,null)
